1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  items: Item[];
9	}
10	
11	interface Customer {
12	  yearsWithMHPCO: number;
13	}
14	
15	const PROCESSING_FEE = 5;
16	const FIRST_INSURANCE_SURCHARGE = 0.1;
17	const CURSE_SURCHARGE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT = 0.2;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const FOLLOWUP_DISCOUNT = 0.15;
23	
24	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const COMPONENT_TYPES = ["rune", "moonstone"];
32	const COMPONENT_PREMIUM = 25;
33	const BLOCK_SIZE = 3;
34	const BLOCK_PREMIUM = 60;
35	
36	// Sum `valueOf` applied to each element of an iterable.
37	const sumOf = <T>(values: Iterable<T>, valueOf: (value: T) => number): number => {
38	  let sum = 0;
39	  for (const value of values) sum += valueOf(value);
40	  return sum;
41	};
42	
43	const isComponent = (item: Item): boolean =>
44	  COMPONENT_TYPES.includes(item.type);
45	
46	const isMainItem = (item: Item): boolean => !isComponent(item);
47	
48	// A group of exactly BLOCK_SIZE alike components is priced at the discounted
49	// BLOCK_PREMIUM; any other count is priced per component.
50	const componentGroupBasePremium = (count: number): number =>
51	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
52	
53	// An item-specific surcharge adds `rate` of the item's base premium when its
54	// condition holds, and nothing otherwise.
55	const surchargeWhen = (item: Item, applies: boolean, rate: number): number =>
56	  applies ? rate * basePremiumForItem(item) : 0;
57	
58	// Cursed items add a surcharge equal to CURSE_SURCHARGE of their base premium.
59	const curseSurcharge = (item: Item): number =>
60	  surchargeWhen(item, item.cursed ?? false, CURSE_SURCHARGE);
61	
62	// Highly enchanted items (enchantment at or above the threshold) add a
63	// surcharge equal to HIGH_ENCHANTMENT_SURCHARGE of their base premium.
64	const highEnchantmentSurcharge = (item: Item): number =>
65	  surchargeWhen(
66	    item,
67	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
68	    HIGH_ENCHANTMENT_SURCHARGE,
69	  );
70	
71	// Premiums are rounded UP, in MHPCO's favor. The toFixed(6) collapses
72	// floating-point artifacts (e.g. 197.49999999) so we don't round a value
73	// that is only spuriously above a whole number.
74	const roundUpInMHPCOsFavor = (amount: number): number =>
75	  Math.ceil(Number(amount.toFixed(6)));
76	
77	const basePremiumForItem = (item: Item): number =>
78	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
79	
80	// Each main item is priced on its own.
81	const mainItemsBasePremium = (items: Item[]): number =>
82	  sumOf(items, basePremiumForItem);
83	
84	const countByType = (items: Item[]): Map<string, number> => {
85	  const counts = new Map<string, number>();
86	  for (const item of items) {
87	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
88	  }
89	  return counts;
90	};
91	
92	// Components are grouped by type, and each group is block-priced.
93	const componentsBasePremium = (components: Item[]): number =>
94	  sumOf(countByType(components).values(), componentGroupBasePremium);
95	
96	const policyBasePremium = (items: Item[]): number =>
97	  mainItemsBasePremium(items.filter(isMainItem)) +
98	  componentsBasePremium(items.filter(isComponent));
99	
100	// Tier 1 — item-specific surcharges: computed off each affected item's base
101	// premium and summed across the policy. (e.g. curse; later high-enchantment.)
102	const itemSurcharges = (items: Item[]): number =>
103	  sumOf(items, (item) => curseSurcharge(item) + highEnchantmentSurcharge(item));
104	
105	// A policy-wide modifier adds `rate` of the policy base premium when its
106	// condition holds, and nothing otherwise.
107	const fractionOfPolicyBaseWhen = (
108	  policyBase: number,
109	  applies: boolean,
110	  rate: number,
111	): number => (applies ? rate * policyBase : 0);
112	
113	// Every new policy carries a surcharge equal to FIRST_INSURANCE_SURCHARGE of
114	// the policy base premium. It always applies, so it is computed directly
115	// rather than going through the conditional fractionOfPolicyBaseWhen helper.
116	const firstInsuranceSurcharge = (policyBase: number): number =>
117	  FIRST_INSURANCE_SURCHARGE * policyBase;
118	
119	// Long-standing customers (at or above the loyalty threshold) receive a
120	// discount equal to LOYALTY_DISCOUNT of the policy base premium.
121	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
122	  fractionOfPolicyBaseWhen(
123	    policyBase,
124	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
125	    LOYALTY_DISCOUNT,
126	  );
127	
128	// Every contract after the customer's first (a non-zero quote index) receives a
129	// discount equal to FOLLOWUP_DISCOUNT of the policy base premium.
130	const followUpDiscount = (policyBase: number, quoteIndex: number): number =>
131	  fractionOfPolicyBaseWhen(policyBase, quoteIndex >= 1, FOLLOWUP_DISCOUNT);
132	
133	// Tier 2 — policy-wide modifiers: each computed as a fraction of the policy
134	// base premium. Surcharges add; discounts subtract. (first-insurance surcharge,
135	// loyalty discount, follow-up discount.)
136	const policyWideModifiers = (
137	  policyBase: number,
138	  customer: Customer,
139	  quoteIndex: number,
140	): number =>
141	  firstInsuranceSurcharge(policyBase) -
142	  loyaltyDiscount(policyBase, customer) -
143	  followUpDiscount(policyBase, quoteIndex);
144	
145	export const quote = (
146	  customer: Customer,
147	  step: QuoteStep,
148	  quoteIndex: number,
149	): number => {
150	  const policyBase = policyBasePremium(step.items);
151	
152	  const total =
153	    policyBase +
154	    itemSurcharges(step.items) +
155	    policyWideModifiers(policyBase, customer, quoteIndex) +
156	    PROCESSING_FEE;
157	  return roundUpInMHPCOsFavor(total);
158	};
159	
160	interface Damage {
161	  itemType: string;
162	  amount: number;
163	}
164	
165	interface Incident {
166	  cause: string;
167	  damages: Damage[];
168	}
169	
170	interface ClaimResult {
171	  payout: number;
172	  remainingCap: number;
173	}
174	
175	const DEDUCTIBLE = 100;
176	
177	// What MHPCO reimburses for a single damage: the damage amount less the
178	// per-damage deductible.
179	const reimbursementForDamage = (damage: Damage): number =>
180	  damage.amount - DEDUCTIBLE;
181	
182	export const claim = (policyItems: Item[], incident: Incident): ClaimResult => {
183	  const payout = sumOf(incident.damages, reimbursementForDamage);
184	  return { payout, remainingCap: 0 };
185	};
